public class BSTSearch {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static TreeNode search(TreeNode r, int t){
        if(r==null||r.val==t)return r;
        return t<r.val?search(r.left,t):search(r.right,t);}
    public static void main(String[] a){
        TreeNode r=new TreeNode(4);r.left=new TreeNode(2);r.right=new TreeNode(7);
        r.left.left=new TreeNode(1);r.left.right=new TreeNode(3);
        System.out.println(search(r,2).val); // 2
        System.out.println(search(r,5));      // null
        System.out.println("O(h): h=log n balanced, h=n skewed. Always prefer balanced BST.");
    }
}

public class BSTInsert {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static TreeNode insert(TreeNode r, int v){
        if(r==null)return new TreeNode(v);
        if(v<r.val)r.left=insert(r.left,v);
        else if(v>r.val)r.right=insert(r.right,v);
        return r;}
    static String inorder(TreeNode r){return r==null?"":inorder(r.left)+r.val+" "+inorder(r.right);}
    public static void main(String[] a){
        TreeNode r=new TreeNode(4);r=insert(r,2);r=insert(r,7);r=insert(r,1);r=insert(r,3);
        System.out.println(inorder(r).trim()); // 1 2 3 4 7
        System.out.println("Insert preserves BST property. Inorder must be sorted after.");
    }
}

public class ValidBST {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static boolean valid(TreeNode r, long lo, long hi){
        if(r==null)return true;
        if(r.val<=lo||r.val>=hi)return false;
        return valid(r.left,lo,r.val)&&valid(r.right,r.val,hi);}
    static boolean isValidBST(TreeNode r){return valid(r,Long.MIN_VALUE,Long.MAX_VALUE);}
    public static void main(String[] a){
        TreeNode r=new TreeNode(2);r.left=new TreeNode(1);r.right=new TreeNode(3);
        System.out.println(isValidBST(r)); // true
        TreeNode bad=new TreeNode(5);bad.left=new TreeNode(1);bad.right=new TreeNode(4);
        bad.right.left=new TreeNode(3);bad.right.right=new TreeNode(6);
        System.out.println(isValidBST(bad)); // false
        System.out.println("Pass (lo,hi) bounds. Long.MIN/MAX handles Integer.MIN_VALUE edge case.");
    }
}

public class KthSmall {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static int k,res;
    static void inorder(TreeNode r){if(r==null)return;inorder(r.left);if(--k==0)res=r.val;inorder(r.right);}
    static int kthSmallest(TreeNode r, int kk){k=kk;inorder(r);return res;}
    public static void main(String[] a){
        TreeNode r=new TreeNode(3);r.left=new TreeNode(1);r.right=new TreeNode(4);r.left.right=new TreeNode(2);
        System.out.println(kthSmallest(r,1)); // 1
        System.out.println(kthSmallest(r,3)); // 3
        System.out.println("BST inorder = sorted. Stop (decrement counter) at kth visit.");
    }
}

public class LCABST2 {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static TreeNode lca(TreeNode r, int p, int q){
        if(p<r.val&&q<r.val)return lca(r.left,p,q);
        if(p>r.val&&q>r.val)return lca(r.right,p,q);
        return r;}
    public static void main(String[] a){
        TreeNode r=new TreeNode(6);r.left=new TreeNode(2);r.right=new TreeNode(8);
        r.left.left=new TreeNode(0);r.left.right=new TreeNode(4);
        System.out.println(lca(r,2,8).val); // 6
        System.out.println(lca(r,2,4).val); // 2
        System.out.println("BST LCA is O(h), not O(n). Use BST property to navigate.");
    }
}

public class BSTDel {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static TreeNode delete(TreeNode r, int k){
        if(r==null)return null;
        if(k<r.val)r.left=delete(r.left,k);
        else if(k>r.val)r.right=delete(r.right,k);
        else{
            if(r.left==null)return r.right;
            if(r.right==null)return r.left;
            TreeNode s=r.right;while(s.left!=null)s=s.left;
            r.val=s.val;r.right=delete(r.right,s.val);}
        return r;}
    static String in(TreeNode r){return r==null?"":in(r.left)+r.val+" "+in(r.right);}
    public static void main(String[] a){
        TreeNode r=new TreeNode(5);r.left=new TreeNode(3);r.right=new TreeNode(6);
        r.left.left=new TreeNode(2);r.left.right=new TreeNode(4);r.right.right=new TreeNode(7);
        System.out.println(in(delete(r,3)).trim()); // 2 4 5 6 7
        System.out.println("2-child delete: replace with inorder successor (leftmost of right subtree)");
    }
}

public class SortedBST {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static TreeNode build(int[] nums, int l, int r){
        if(l>r)return null;int mid=(l+r)/2;
        TreeNode n=new TreeNode(nums[mid]);
        n.left=build(nums,l,mid-1);n.right=build(nums,mid+1,r);return n;}
    static int depth(TreeNode r){return r==null?0:1+Math.max(depth(r.left),depth(r.right));}
    public static void main(String[] a){
        int[] nums={-10,-3,0,5,9};
        TreeNode r=build(nums,0,nums.length-1);
        System.out.println(depth(r));   // 3
        System.out.println(r.val);      // 0 (middle element)
        System.out.println("Mid element as root → balanced. O(n) to build.");
    }
}

import java.util.*;
public class BSTIter {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static class BSTIterator{
        Deque<TreeNode> st=new ArrayDeque<>();
        BSTIterator(TreeNode r){pushLeft(r);}
        void pushLeft(TreeNode n){while(n!=null){st.push(n);n=n.left;}}
        int next(){TreeNode n=st.pop();pushLeft(n.right);return n.val;}
        boolean hasNext(){return!st.isEmpty();}}
    public static void main(String[] a){
        TreeNode r=new TreeNode(7);r.left=new TreeNode(3);r.right=new TreeNode(15);
        r.right.left=new TreeNode(9);r.right.right=new TreeNode(20);
        BSTIterator it=new BSTIterator(r);
        System.out.println(it.next()); // 3
        System.out.println(it.next()); // 7
        System.out.println(it.hasNext()); // true
        System.out.println("O(h) space stack. next() amortized O(1). pushLeft on right after pop.");
    }
}

public class GreaterTree {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static int sum=0;
    static void revInorder(TreeNode r){
        if(r==null)return;revInorder(r.right);sum+=r.val;r.val=sum;revInorder(r.left);}
    public static void main(String[] a){
        TreeNode r=new TreeNode(4);r.left=new TreeNode(1);r.right=new TreeNode(6);
        r.left.right=new TreeNode(2);r.right.left=new TreeNode(5);r.right.right=new TreeNode(7);
        sum=0;revInorder(r);
        System.out.println(r.val);       // 22 (4+6+5+7)
        System.out.println(r.right.val); // 13 (6+7)
        System.out.println("Reverse inorder (R-N-L): accumulate suffix sum from largest to smallest");
    }
}

public class RecoverBST {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static TreeNode first=null,second=null,prev=null;
    static void inorder(TreeNode r){
        if(r==null)return;inorder(r.left);
        if(prev!=null&&prev.val>r.val){if(first==null)first=prev;second=r;}
        prev=r;inorder(r.right);}
    static void recoverTree(TreeNode r){first=second=prev=null;inorder(r);int t=first.val;first.val=second.val;second.val=t;}
    static String in(TreeNode r){return r==null?"":in(r.left)+r.val+" "+in(r.right);}
    public static void main(String[] a){
        TreeNode r=new TreeNode(1);r.left=new TreeNode(3);r.left.right=new TreeNode(2);
        recoverTree(r);System.out.println(in(r).trim());
        System.out.println("Find two swapped nodes via inorder: first violation = first, second violation = second");
    }
}

public class BSTSynth {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static boolean valid(TreeNode r,long lo,long hi){if(r==null)return true;if(r.val<=lo||r.val>=hi)return false;return valid(r.left,lo,r.val)&&valid(r.right,r.val,hi);}
    static TreeNode ins(TreeNode r,int v){if(r==null)return new TreeNode(v);if(v<r.val)r.left=ins(r.left,v);else if(v>r.val)r.right=ins(r.right,v);return r;}
    static int kth(TreeNode r,int k){int[]c={k},res={-1};ih(r,c,res);return res[0];}
    static void ih(TreeNode r,int[]c,int[]res){if(r==null)return;ih(r.left,c,res);if(--c[0]==0)res[0]=r.val;ih(r.right,c,res);}
    static String in(TreeNode r){return r==null?"":in(r.left)+r.val+" "+in(r.right);}
    public static void main(String[] a){
        TreeNode r=new TreeNode(4);r=ins(r,2);r=ins(r,6);r=ins(r,1);r=ins(r,3);
        System.out.println("valid="+valid(r,Long.MIN_VALUE,Long.MAX_VALUE));
        System.out.println("kth2="+kth(r,2));
        System.out.println("inorder="+in(r).trim());
        boolean ok=valid(r,Long.MIN_VALUE,Long.MAX_VALUE)&&kth(r,2)==2&&in(r).trim().equals("1 2 3 4 6");
        System.out.println("All pass: "+ok);
    }
}

public class T3Final {
    static class TreeNode{int val;TreeNode left,right;TreeNode(int v){val=v;}}
    static boolean valid(TreeNode r,long lo,long hi){if(r==null)return true;if(r.val<=lo||r.val>=hi)return false;return valid(r.left,lo,r.val)&&valid(r.right,r.val,hi);}
    static TreeNode del(TreeNode r,int k){if(r==null)return null;if(k<r.val)r.left=del(r.left,k);else if(k>r.val)r.right=del(r.right,k);else{if(r.left==null)return r.right;if(r.right==null)return r.left;TreeNode s=r.right;while(s.left!=null)s=s.left;r.val=s.val;r.right=del(r.right,s.val);}return r;}
    static int kth(TreeNode r,int k){int[]c={k},res={-1};ih(r,c,res);return res[0];}
    static void ih(TreeNode r,int[]c,int[]res){if(r==null)return;ih(r.left,c,res);if(--c[0]==0)res[0]=r.val;ih(r.right,c,res);}
    static String in(TreeNode r){return r==null?"":in(r.left)+r.val+" "+in(r.right);}
    public static void main(String[] a){
        TreeNode r=new TreeNode(5);r.left=new TreeNode(3);r.right=new TreeNode(6);r.left.left=new TreeNode(2);r.left.right=new TreeNode(4);
        System.out.println("valid="+valid(r,Long.MIN_VALUE,Long.MAX_VALUE));
        System.out.println("kth3="+kth(r,3));
        System.out.println("del3="+in(del(r,3)).trim());
        boolean ok=valid(r,Long.MIN_VALUE,Long.MAX_VALUE)&&kth(r,3)==4;
        System.out.println("All pass: "+ok);
    }
}
